 1→const API_BASE = import.meta.env.VITE_API_BASE_URL ?? "http://localhost:8000";
 2→
 3→async function http<T>(path: string): Promise<T> {
 4→  const res = await fetch(`${API_BASE}${path}`);
 5→  if (!res.ok) {
 6→    const msg = await res.text().catch(() => "");
 7→    throw new Error(`HTTP ${res.status} ${res.statusText}${msg ? ` - ${msg}` : ""}`);
 8→  }
 9→  return res.json() as Promise<T>;
10→}
11→
